  ('cpa-moex-00705', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '下列關於召集董事會之敘述，何者正確？', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00706', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A股份有限公司近年來跨足太陽能產業，導致公司連年虧損，於民國107年6月20日股東常會 甫決議通過虧損撥補議案。同年7月時，大陸突然宣布給予其太陽能產業價格補貼，致我國太陽 能產業全面遭受巨額損失。因業務需要，於同年 8 月會計師查核簽證財務報告時，發現 A 公司 實際虧損竟已達實收資本額二分之一，則依公司法，A公司應如何處理？', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
